  .clickable-path {
    cursor: pointer;
    transition:
      fill 180ms $ease-power2-out,
      stroke 180ms $ease-power2-out,
      filter 180ms $ease-power2-out;

    &:focus,
    &:focus-visible {
      outline: none;
    }

    &:hover,
    &:focus-visible {
      fill: $color-yellow-base !important;
      stroke: $color-white-base !important;
      filter: brightness(1.02);
    }

    &.is-active {
      fill: $color-yellow-base !important;
      stroke: $color-white-base !important;
      filter: brightness(1.02);
    }

    &.is-hovered {
      fill: $color-yellow-base !important;
      stroke: $color-white-base !important;
      filter: brightness(1.02);
    }
  }

  .iconLabel {
    position: absolute;
    transform: translate(-0%, -50%);
